<body>
  <div class="container">
    <h1>Client-Side Journal Analyzer</h1>
    <div id="root"></div>
  </div>

  <!-- React + Babel (no build pipeline) -->
  <script crossorigin src="https://unpkg.com/react@18/umd/react.development.js"></script>
  <script crossorigin src="https://unpkg.com/react-dom@18/umd/react-dom.development.js"></script>
  <script src="https://unpkg.com/@babel/standalone/babel.min.js"></script>

  <!-- PDF.js for PDF text extraction -->
  <script src="https://cdnjs.cloudflare.com/ajax/libs/pdf.js/4.4.168/pdf.min.js" integrity="sha512-5Yd3f5+OeY7vX3sBqK+fVd2Je2v0qF2v8yEyyF9W4vYVZg8o5pWzQ/7nIglV8dBvCqzK7l+Oq8nry0rKq6wSA==" crossorigin="anonymous" referrerpolicy="no-referrer"></script>

  <script type="text/babel">
    const { useMemo, useState } = React;

    function normalizeWhitespace(s) {
      return (s || "").replace(/\r\n/g, "\n").replace(/\t/g, " ");
    }

    function countCitations(text) {
      // bracket style citations like [1], [42]
      const m = (text || "").match(/\[\d+\]/g);
      return m ? m.length : 0;
    }

    function tokenizeWords(text) {
      // Keep it simple + consistent: words are A-Z sequences with optional apostrophes
      const m = (text || "").toLowerCase().match(/[a-z]+(?:'[a-z]+)?/g);
      return m || [];
    }

    function keywordStats(text) {
      const words = tokenizeWords(text);
      const totalWords = words.length;
      const counts = { quantum: 0, entanglement: 0 };
      for (const w of words) {
        if (w === "quantum") counts.quantum++;
        if (w === "entanglement") counts.entanglement++;
      }
      const density = (count) => {
        if (!totalWords) return 0;
        return Number((count / totalWords).toFixed(3));
      };
      return {
        totalWords,
        keywordDensity: {
          quantum: { count: counts.quantum, density: density(counts.quantum) },
          entanglement: { count: counts.entanglement, density: density(counts.entanglement) }
        }
      };
    }

    function splitIntoSentences(block) {
      // Lightweight sentence splitting: end punctuation followed by whitespace/newline.
      const cleaned = (block || "").replace(/\s+/g, " ").trim();
      if (!cleaned) return [];
      // Preserve the punctuation.
      const parts = cleaned.split(/(?<=[.!?])\s+/);
      return parts.map(s => s.trim()).filter(Boolean);
    }

    function summarizeMarkdown(mdText) {
      const text = normalizeWhitespace(mdText);
      const lines = text.split("\n");

      const sections = [];
      let current = null;

      const pushCurrent = () => {
        if (current) sections.push(current);
      };

      for (let i = 0; i < lines.length; i++) {
        const line = lines[i];
        const headerMatch = line.match(/^\s*#+\s+(.*)\s*$/);
        if (headerMatch) {
          pushCurrent();
          current = { title: headerMatch[1].trim(), bodyLines: [] };
        } else {
          if (!current) {
            // content before any header goes into a synthetic section
            current = { title: "(Intro)", bodyLines: [] };
          }
          current.bodyLines.push(line);
        }
      }
      pushCurrent();

      return sections.map(sec => {
        const body = sec.bodyLines.join("\n");
        // Find first non-empty sentence under heading
        const firstNonEmptyLineIndex = sec.bodyLines.findIndex(l => l.trim().length > 0);
        let candidateText = "";
        if (firstNonEmptyLineIndex >= 0) {
          candidateText = sec.bodyLines.slice(firstNonEmptyLineIndex).join(" ");
        }
        const sentences = splitIntoSentences(candidateText);
        const summary = sentences[0] || "";
        return { title: sec.title, summary };
      }).filter(s => (s.title && s.title.trim().length) || (s.summary && s.summary.trim().length));
    }

    function recoverHeadingsFromText(rawText) {
      // Heuristic: headings are short lines (<= 80 chars) that are either ALL CAPS
      // or Title-like and surrounded by blank lines.
      const text = normalizeWhitespace(rawText);
      const lines = text.split("\n").map(l => l.replace(/\s+/g, " ").trim());

      const sections = [];
      let current = { title: "(Intro)", bodyLines: [] };

      function looksLikeHeading(line) {
        if (!line) return false;
        if (line.length > 80) return false;
        // Exclude lines that look like page numbers or figure/table labels
        if (/^\d+$/.test(line)) return false;
        if (/^(figure|fig\.|table)\b/i.test(line)) return false;

        const letters = line.replace(/[^A-Za-z]/g, "");
        if (!letters) return false;

        const isAllCaps = line === line.toUpperCase() && /[A-Z]/.test(line);
        const isTitleCaseish = /^[A-Z][A-Za-z0-9\s\-:;,()]+$/.test(line);
        return isAllCaps || isTitleCaseish;
      }

      for (let i = 0; i < lines.length; i++) {
        const line = lines[i];
        const prev = i > 0 ? lines[i - 1] : "";
        const next = i + 1 < lines.length ? lines[i + 1] : "";

        const boundary = (!prev && !!line) || (!next && !!line) || (!prev && !next);
        const headingCandidate = looksLikeHeading(line) && (prev === "" || next === "") && !boundary;

        if (headingCandidate) {
          // push current and start new
          sections.push(current);
          current = { title: line, bodyLines: [] };
        } else {
          current.bodyLines.push(line);
        }
      }
      sections.push(current);

      return sections
        .map(sec => {
          const body = sec.bodyLines.join(" ").trim();
          const sentences = splitIntoSentences(body);
          return { title: sec.title, summary: sentences[0] || "" };
        })
        .filter(s => (s.title && s.title.trim().length) || (s.summary && s.summary.trim().length));
    }

    async function extractPdfText(file) {
      // Using PDF.js to extract text content
      if (!window.pdfjsLib) {
        throw new Error("PDF.js failed to load");
      }
      // worker
      try {
        const workerSrc = "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/4.4.168/pdf.worker.min.js";
        window.pdfjsLib.GlobalWorkerOptions.workerSrc = workerSrc;
      } catch (e) {
        // ignore
      }

      const buf = await file.arrayBuffer();
      const pdf = await window.pdfjsLib.getDocument({ data: buf }).promise;

      let fullText = "";
      for (let p = 1; p <= pdf.numPages; p++) {
        const page = await pdf.getPage(p);
        const content = await page.getTextContent();
        const strings = content.items.map(it => (it.str || "").trim()).filter(Boolean);
        // Separate items with spaces; add newlines between pages to help headings heuristics.
        fullText += strings.join(" ") + "\n\n";
      }
      return fullText;
    }

    function analyzeText({ fileType, text }) {
      const citations = countCitations(text);
      const { totalWords, keywordDensity } = keywordStats(text);

      let sectionSummaries = [];
      if (fileType === "markdown") {
        sectionSummaries = summarizeMarkdown(text);
      } else if (fileType === "pdf") {
        // Try to recover headings and then summarize
        sectionSummaries = recoverHeadingsFromText(text);
      } else {
        sectionSummaries = [{ title: "(Content)", summary: splitIntoSentences(text)[0] || "" }];
      }

      return {
        fileType,
        citations,
        totalWords,
        keywordDensity,
        sectionSummaries
      };
    }

    function App() {
      const [status, setStatus] = useState("No file loaded.");
      const [analysis, setAnalysis] = useState({
        fileType: null,
        citations: 0,
        totalWords: 0,
        keywordDensity: {
          quantum: { count: 0, density: 0 },
          entanglement: { count: 0, density: 0 }
        },
        sectionSummaries: []
      });

      const jsonMirror = useMemo(() => {
        // Ensure consistent JSON shape and always valid JSON
        return JSON.stringify(analysis, null, 2);
      }, [analysis]);

      async function onFileChange(e) {
        const file = e.target.files && e.target.files[0];
        if (!file) return;

        const name = file.name.toLowerCase();
        const isMd = name.endsWith(".md") || name.endsWith(".markdown");
        const isPdf = name.endsWith(".pdf");

        if (!isMd && !isPdf) {
          setStatus("Unsupported file type. Please choose .md, .markdown, or .pdf.");
          return;
        }

        try {
          setStatus(`Loading ${file.name}...`);
          if (isMd) {
            const text = await file.text();
            const result = analyzeText({ fileType: "markdown", text });
            setAnalysis(result);
            setStatus(`Analyzed ${file.name}.`);
          } else if (isPdf) {
            setStatus(`Extracting text from ${file.name}...`);
            const text = await extractPdfText(file);
            const result = analyzeText({ fileType: "pdf", text });
            setAnalysis(result);
            setStatus(`Analyzed ${file.name}.`);
          }
        } catch (err) {
          console.error(err);
          setStatus(`Error: ${err && err.message ? err.message : String(err)}`);
        }
      }

      return (
        <div>
          <div className="card">
            <label>
              <div><strong>Upload journal file</strong></div>
              <input
                type="file"
                accept=".md,.markdown,.pdf"
                onChange={onFileChange}
              />
            </label>
            <div className="status muted">{status}</div>
          </div>

          <div className="row">
            <div className="card">
              <h3>Citation Frequency</h3>
              <div><strong>Total citations:</strong> {analysis.citations}</div>
            </div>

            <div className="card">
              <h3>Keyword Density</h3>
              <div><strong>Total words:</strong> {analysis.totalWords}</div>
              <div style={{ marginTop: 8 }}>
                <div><strong>quantum</strong> — count: {analysis.keywordDensity.quantum.count}, density: {analysis.keywordDensity.quantum.density}</div>
                <div><strong>entanglement</strong> — count: {analysis.keywordDensity.entanglement.count}, density: {analysis.keywordDensity.entanglement.density}</div>
              </div>
            </div>
          </div>

          <div className="card">
            <h3>Section Summaries</h3>
            <div className="sections">
              {analysis.sectionSummaries && analysis.sectionSummaries.length ? (
                analysis.sectionSummaries.map((s, idx) => (
                  <div key={idx}>
                    <div><strong>{s.title}</strong></div>
                    <div className="muted">{s.summary || ""}</div>
                  </div>
                ))
              ) : (
                <div className="muted">No sections yet. Upload a file to generate summaries.</div>
              )}
            </div>
          </div>

          <div className="card">
            <div className="muted" style={{ marginBottom: 8 }}>
              Machine-readable analysis mirror (JSON):
            </div>
            <pre id="analysis-output">{jsonMirror}</pre>
          </div>
        </div>
      );
    }

    ReactDOM.createRoot(document.getElementById('root')).render(<App />);
  </script>
</body>
</html>
